function bfL(bf,s){if(s==="male"){if(bf<=8)return{l:"Shredded",c:"#30d158"};if(bf<=14)return{l:"Athletic",c:"#34c759"};if(bf<=17)return{l:"Fit",c:"#0a84ff"};if(bf<=24)return{l:"Average",c:"#ffd60a"};return{l:"Above Avg",c:"#ff9f0a"};}if(bf<=22)return{l:"Athletic",c:"#34c759"};if(bf<=25)return{l:"Fit",c:"#0a84ff"};if(bf<=31)return{l:"Average",c:"#ffd60a"};return{l:"Above Avg",c:"#ff9f0a"};}
function cTDEE(w,h,a,s,act,met,bf){const wK=w*0.4536,hC=h*2.54;let bmr;if(bf&&bf>0&&bf<60){const lbm=wK*(1-bf/100);bmr=370+21.6*lbm;}else{bmr=s==="male"?10*wK+6.25*hC-5*a+5:10*wK+6.25*hC-5*a-161;}const m=act==="Not training"?1.2:act==="1-2x/week"?1.375:act==="3-4x/week"?1.55:1.725;const mm=met==="fast"?1.08:met==="slow"?0.95:1.0;return Math.round(bmr*m*mm);}
