const pickExercises=(type,recent,prof)=>{const pool=EX_POOL[type];if(!pool)return[];const recentSet=new Set((recent||[]).map(e=>e.n||e.name));const goal=prof&&prof.cBF&&prof.gBF?(+prof.cBF>+prof.gBF?"cut":"bulk"):"recomp";const picks=[];const groups=Object.keys(pool);groups.forEach(g=>{const avail=pool[g].filter(e=>!recentSet.has(e.n));const use=avail.length>=2?avail:pool[g];const shuffled=[...use].sort(()=>Math.random()-0.5);const count=g==="Calves"?1:(g==="RearDelts"?1:(g==="Triceps"||g==="Biceps"?2:2));for(let i=0;i<Math.min(count,shuffled.length);i++)picks.push(shuffled[i]);});return picks.slice(0,6);};
