export default function App(){
  const[prof,setProf]=useState(null);const[logs,setLogs]=useState({});const[loading,setLoading]=useState(true);const[scr,setScr]=useState("welcome");
  useEffect(()=>{(async()=>{if(!getToken()){setLoading(false);return;}try{const d=await getMe();setProf(d.user.profile);setLogs(d.logs||{});setScr("app");}catch(e){}setLoading(false);})();},[]);
  const saveTimer=useRef(null);const lastCount=useRef(0);const sL=useCallback(fn=>{setLogs(p=>{const n=typeof fn==="function"?fn(p):fn;const today=ds();if(n[today]){const d=n[today];const count=(d.b||[]).length+(d.l||[]).length+(d.s||[]).length+(d.d||[]).length+(d.myEx||[]).length+(d.drinks||[]).length+(d.cardio||[]).length+(d.woPush||[]).length+(d.woPull||[]).length+(d.woLegs||[]).length;const added=count>lastCount.current;lastCount.current=count;if(saveTimer.current)clearTimeout(saveTimer.current);saveTimer.current=setTimeout(()=>{saveLog(today,d).then(()=>{setSaved(true);setTimeout(()=>setSaved(false),1500);}).catch(()=>{setTimeout(()=>saveLog(today,d).catch(()=>{}),3000);});},800);if(added||d.woSub||d.closed||d.missConfirmed||d.wAM||d.wPM||['woPush','woPull','woLegs'].some(k=>(d[k]||[]).some(e=>e.log&&e.log.some(s=>s.w||s.r)))){saveLog(today,d).catch(()=>{});}}return n;});},[]);
  const sP=useCallback(p=>{setProf(p);updateProfile(p);},[]);
  const login=async(u,pw)=>{try{const d=await apiLoginFn(u,pw);const up=Object.assign({},d.user.profile,{isPaid:true});setProf(up);setLogs(d.logs||{});setScr("app");return null;}catch(e){return e.message;}};
  const create=async(u,pw,p)=>{try{await apiSignup(u,pw,(p.name+(p.lastName?" "+p.lastName:"")),{...p,aiConsent:true});setProf({...p,aiConsent:true});setLogs({});setScr("paywall");}catch(e){return e.message;}return null;};
  const deleteAccount=async()=>{if(!window.confirm("Permanently delete your account and all data? This cannot be undone."))return;const t=localStorage.getItem("token")||sessionStorage.getItem("token");if(t)await fetch("/api/user/delete",{method:"DELETE",headers:{"Authorization":"Bearer "+t}}).catch(()=>{});apiLogoutFn();setProf(null);setLogs({});setScr("welcome");};const logout=async()=>{apiLogoutFn();setProf(null);setLogs({});setScr("welcome");};
  if(loading) return <div style={{fontFamily:FF,background:"#000",color:"#fff",minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{fontSize:14,fontWeight:800,letterSpacing:6,WebkitTextStroke:"0.6px #e8372c",paintOrder:"stroke fill"}}>CALIBR<span style={{color:"#e8372c",letterSpacing:0,fontSize:"108%",position:"relative",top:"0.05em"}}>8</span></div></div>;
  if(scr==="welcome") return <WL go={()=>setScr("onboard")} goLogin={()=>setScr("login")}/>;
  if(scr==="login") return <LG onLogin={login} back={()=>setScr("welcome")} goNew={()=>setScr("onboard")}/>;
  if(scr==="onboard") return <OB onCreate={create} back={()=>setScr("welcome")}/>;
  if(scr==="paywall") return <PW onSubscribe={(plan,cd)=>{const p=Object.assign({},prof,{isPaid:true,plan:plan,promoCode:cd});setProf(p);updateProfile(p);setScr("app");}} onSkip={()=>setScr("app")}/>;
  return <MA prof={prof} logs={logs} sL={sL} sP={sP} logout={logout}/>;
}

